function report = runStreamedSgmBenchmark(options)
%RUNSTREAMEDSGMBENCHMARK Gate MAT-file row-slab SGM and target preflight.
%
% Costs are generated and written slab by slab. The benchmark materializes
% its moderate control only for an independent in-memory comparison; the
% streamed method itself retains two slabs plus boundary states.
%
% Traceability: algo/main.tex Sec. 5.6 and Eqs. (71)--(75);
% implementation plan Stages C5 and C7.

arguments
    options.ImageSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [256, 320]
    options.LabelCount (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeGreaterThanOrEqual( ...
        options.LabelCount, 3)} = 21
    options.RowSlabRows (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 64
    options.WorkingPrecision (1, 1) string ...
        {mustBeMember(options.WorkingPrecision, ...
        ["single", "double"])} = "single"
    options.DirectionCount (1, 1) double ...
        {mustBeMember(options.DirectionCount, [4, 8])} = 8
    options.MinimumIoMebibytesPerSecond (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 20
    options.TargetImageSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [5000, 15000]
    options.TargetLabelCount (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 21
    options.TargetMemoryBudgetGiB (1, 1) double ...
        {mustBeFinite, mustBePositive} = 8
    options.OutputDirectory (1, 1) string ...
        {mustBeOutputDirectory} = ""
    options.KeepFiles (1, 1) logical = false
    options.RunInMemoryReference (1, 1) logical = true
end

rngState = rng;
rngCleanup = onCleanup(@() rng(rngState));
rng(20260718, "twister");
createdDirectory = options.OutputDirectory == "";
if createdDirectory
    directory = string(tempname);
    mkdir(directory);
else
    directory = options.OutputDirectory;
end
costFile = string(tempname(directory)) + "_cost.mat";
aggregateFile = string(tempname(directory)) + "_aggregate.mat";
fileCleanup = onCleanup(@() cleanupFiles( ...
    costFile, aggregateFile, directory, ...
    createdDirectory, options.KeepFiles));

nr = options.ImageSize(1);
nc = options.ImageSize(2);
u = linspace(-1, 1, options.LabelCount);
z = 60 .* sign(u) .* abs(u) .^ 1.15;
shape = [nr, nc, options.LabelCount];
m = metadata(z);
costStore = HeightVolumeStore(shape, ...
    Precision=options.WorkingPrecision, Mode="matfile", ...
    FilePath=costFile, Metadata=m);
aggregateStore = HeightVolumeStore(shape, ...
    Precision=options.WorkingPrecision, Mode="matfile", ...
    FilePath=aggregateFile, Metadata=m);
starts = 1:options.RowSlabRows:nr;
generationTimer = tic;
for slab = 1:numel(starts)
    rows = starts(slab):min( ...
        starts(slab) + options.RowSlabRows - 1, nr);
    [x, y] = meshgrid(1:nc, rows);
    truth = 18 .* sin(2 .* pi .* x ./ max(nc, 2)) ...
        .* cos(2 .* pi .* y ./ max(nr, 2));
    c = zeros(numel(rows), nc, options.LabelCount, ...
        options.WorkingPrecision);
    for k = 1:options.LabelCount
        ck = ((z(k) - truth) ./ 60) .^ 2 ...
            + 0.002 .* rand(numel(rows), nc);
        ck(mod(y + 2 .* x + 3 .* k, 97) == 0) = NaN;
        c(:, :, k) = cast(ck, options.WorkingPrecision);
    end
    reset = rows <= 2 | rows == round(nr ./ 2);
    c(repmat(reshape(reset, [], 1, 1), ...
        1, nc, options.LabelCount)) = NaN;
    c(:, 1:min(2, nc), :) = NaN;
    costStore.writeRows(rows, c);
end
generationSeconds = toc(generationTimer);

streamed = HeightSgm.aggregateStreamed( ...
    costStore, aggregateStore, z, ...
    RowSlabRows=options.RowSlabRows, ...
    DirectionCount=options.DirectionCount);
if options.RunInMemoryReference
    cost = costStore.readRows(1:nr);
    storedAggregate = aggregateStore.readRows(1:nr);
    reference = HeightSgm.aggregateVectorized( ...
        cost, z, DirectionCount=options.DirectionCount);
    if options.WorkingPrecision == "double"
        costTolerance = 1e-12;
    else
        costTolerance = 2e-6;
    end
    comparison = HeightSweepEquivalence.compare( ...
        reference.AggregatedCost, storedAggregate, ...
        CostTolerance=costTolerance, TieTolerance=1e-4);
    selectionEqual = isequal(reference.LabelIndex, streamed.LabelIndex) ...
        && isequal(reference.Valid, streamed.Valid);
    referenceSeconds = reference.RuntimeSeconds;
else
    comparison = [];
    selectionEqual = [];
    referenceSeconds = NaN;
end
costStats = costStore.statistics;
aggregateStats = aggregateStore.statistics;
ioBytes = costStats.ReadBytes + costStats.WriteBytes ...
    + aggregateStats.ReadBytes + aggregateStats.WriteBytes;
ioSeconds = costStats.FileIoSeconds + aggregateStats.FileIoSeconds;
if ioSeconds > 0
    ioRate = ioBytes ./ 2 ^ 20 ./ ioSeconds;
else
    ioRate = NaN;
end
preflight = HeightSweepMemoryEstimator.estimate( ...
    options.TargetImageSize, options.TargetLabelCount, ...
    Precision=options.WorkingPrecision, Mode="streamed", ...
    DirectionCount=options.DirectionCount, ...
    RowSlabRows=options.RowSlabRows, ...
    RecomputeBackwardCosts=false, ...
    MemoryBudgetGiB=options.TargetMemoryBudgetGiB);
ioPass = isfinite(ioRate) ...
    && ioRate >= options.MinimumIoMebibytesPerSecond;
storeComplete = costStats.Complete && aggregateStats.Complete;
if options.RunInMemoryReference
    numericalPass = comparison.Pass && selectionEqual;
else
    numericalPass = true;
end
allPass = all([numericalPass, ioPass, ...
    preflight.FitsMemoryBudget, storeComplete]);
costInfo = dir(costFile);
aggregateInfo = dir(aggregateFile);
report = struct( ...
    "ImageSize", options.ImageSize, ...
    "HeightLabelsMetres", z, ...
    "Precision", options.WorkingPrecision, ...
    "DirectionCount", options.DirectionCount, ...
    "RowSlabRows", min(options.RowSlabRows, nr), ...
    "GenerationSeconds", generationSeconds, ...
    "StreamedSeconds", streamed.RuntimeSeconds, ...
    "ReferenceSeconds", referenceSeconds, ...
    "ReferenceComparisonPerformed", options.RunInMemoryReference, ...
    "NumericalComparison", comparison, ...
    "SelectionEqual", selectionEqual, ...
    "StoresComplete", storeComplete, ...
    "CostStoreStatistics", costStats, ...
    "AggregateStoreStatistics", aggregateStats, ...
    "FileIoMebibytesPerSecond", ioRate, ...
    "MinimumIoMebibytesPerSecond", ...
    options.MinimumIoMebibytesPerSecond, ...
    "MatFileAccepted", ioPass, ...
    "CostFileBytes", costInfo.bytes, ...
    "AggregateFileBytes", aggregateInfo.bytes, ...
    "MaximumSlabPayloadBytes", streamed.MaximumSlabPayloadBytes, ...
    "MaximumScanlineStateBytes", ...
    streamed.MaximumScanlineStateBytes, ...
    "RetainedSlabCount", streamed.RetainedSlabCount, ...
    "TargetPreflight", preflight, ...
    "AllPass", allPass, ...
    "CostFile", costFile, ...
    "AggregateFile", aggregateFile, ...
    "FilesRetained", options.KeepFiles, ...
    "ArrayLayout", "[row,column,label]", ...
    "InvalidCost", "NaN", ...
    "PixelConvention", ...
    "one-based [x,y]=[column,row] pixel centers", ...
    "WorldFrame", "local ENU metres", ...
    "ElevationDatum", "local synthetic ENU Z=0");

if options.RunInMemoryReference
    fprintf("Streamed SGM: %.3f s, reference %.3f s, max cost drift " ...
        + "%.3e, labels exact %s\n", streamed.RuntimeSeconds, ...
        referenceSeconds, comparison.MaximumAbsoluteCostDifference, ...
        string(selectionEqual));
else
    fprintf("Streamed SGM: %.3f s, in-memory reference omitted; " ...
        + "stores complete %s\n", streamed.RuntimeSeconds, ...
        string(storeComplete));
end
fprintf("  MAT-file I/O %.3f MiB/s, two-slab payload %.3f MiB, " ...
    + "target RAM %.3f GiB / %.3f GiB; pass %s\n", ...
    ioRate, streamed.MaximumSlabPayloadBytes ./ 2 ^ 20, ...
    preflight.RequestedRamBytes ./ 2 ^ 30, ...
    options.TargetMemoryBudgetGiB, string(allPass));

clear streamed reference costStore aggregateStore
if ~options.KeepFiles
    delete(fileCleanup);
else
    clear fileCleanup
end
clear rngCleanup
end

function m = metadata(z)
m = struct( ...
    "HeightLabelsMetres", z, ...
    "PixelConvention", "one-based [x,y]=[column,row] pixel centers", ...
    "WorldFrame", "local ENU metres", ...
    "ElevationDatum", "local synthetic ENU Z=0", ...
    "ArrayLayout", "[row,column,label]", ...
    "InvalidCost", "NaN");
end

function cleanupFiles(costFile, aggregateFile, directory, ...
        removeDirectory, keepFiles)
if keepFiles
    return
end
if isfile(costFile)
    delete(costFile);
end
if isfile(aggregateFile)
    delete(aggregateFile);
end
if removeDirectory && isfolder(directory)
    rmdir(directory);
end
end

function mustBeOutputDirectory(directory)
if directory ~= "" && ~isfolder(directory)
    error("runStreamedSgmBenchmark:OutputDirectoryNotFound", ...
        "OutputDirectory must already exist.");
end
end
